import{_ as r,M as a,p as s,q as l,R as e,t,N as c,a1 as n}from"./framework-5866ffd3.js";const i={},d=n('<h1 id="llm-相关概念" tabindex="-1"><a class="header-anchor" href="#llm-相关概念" aria-hidden="true">#</a> LLM 相关概念</h1><h2 id="function-call-函数调用" tabindex="-1"><a class="header-anchor" href="#function-call-函数调用" aria-hidden="true">#</a> Function Call（函数调用）</h2><p>Function Call 指 LLM 在生成自然语言之外，还能按约定输出<strong>结构化数据</strong>（常见为 JSON），用来表示「要调用哪个外部函数、参数是什么」。借此可以把模型输出接到代码、HTTP API、数据库、脚本等，实现与真实系统的交互。</p><p>多数云厂商与开源栈会把它和 <strong>JSON Schema</strong>（或等价描述）绑定：先声明工具名与参数类型，模型只负责在合法集合里做选择并填参；真正执行仍由宿主程序完成。这是许多「工具使用 / Tool Use」方案的底层能力，Agent、MCP 等往往都建立在这层之上。</p><h2 id="agent" tabindex="-1"><a class="header-anchor" href="#agent" aria-hidden="true">#</a> Agent</h2><p>Agent 一般指 <strong>LLM + 工具 + 记忆 + 编排逻辑</strong> 构成的智能体：不局限于单次问答，而是能在多步里<strong>推理 → 选工具 → 执行 → 根据结果再推理</strong>，直到任务结束或达到终止条件。</p><p>与「只聊天」的用法相比，Agent 强调<strong>闭环</strong>：模型决定下一步动作，环境返回观测结果，再进入下一轮。记忆可以是会话摘要、向量检索、键值存储等形式，视产品而定。</p><h2 id="mcp-model-context-protocol" tabindex="-1"><a class="header-anchor" href="#mcp-model-context-protocol" aria-hidden="true">#</a> MCP（Model Context Protocol）</h2>',8),h={href:"https://modelcontextprotocol.io/",target:"_blank",rel:"noopener noreferrer"},g=e("strong",null,"开放协议",-1),p=n('<p>对模型侧而言，MCP 服务会提供<strong>能力声明</strong>：有哪些工具、每个工具的参数与说明。宿主在启动或连接时会拉取这份声明；用户提问时，模型在需要时发起工具调用，由 MCP 执行并返回结果，再用于生成最终回复。可以理解为：<strong>把一类集成方式标准化</strong>，便于同一套 MCP 被多个宿主复用。</p><h2 id="skill-技能" tabindex="-1"><a class="header-anchor" href="#skill-技能" aria-hidden="true">#</a> Skill（技能）</h2><p>Skill 常指<strong>可复用的技能说明</strong>：不限于「可调用的 API」，也可以描述<strong>规范、流程、约定、检查清单</strong>等。形式上多为 Markdown 等文档，开头常有<strong>摘要</strong>，正文展开细节与示例。</p><p>与 Agent 结合时，典型做法是：先只把各 Skill 的摘要注入上下文，让模型知道「有哪些技能」；当判断某条用户任务匹配某一 Skill 时，再<strong>按需加载</strong>该 Skill 全文，并按文档约束调整行为（例如优先用某类工具、遵守某套步骤）。这和单纯堆长提示词的区别在于：<strong>分层加载</strong>，节省上下文并减少干扰。</p>',4);function _(m,f){const o=a("ExternalLinkIcon");return s(),l("div",null,[d,e("p",null,[e("a",h,[t("MCP"),c(o)]),t(" 是一套"),g,t("，用来把「工具、资源、提示」等能力以标准方式暴露给支持 MCP 的客户端（如部分 IDE、桌面应用）。实现上常见为本地或远程进程，通过约定好的传输层与宿主通信。")]),p])}const x=r(i,[["render",_],["__file","llm.html.vue"]]);export{x as default};
